    var maxProfit = 0L

    // Calculate the original profit
    for (i in strategy.indices) {
        maxProfit += strategy[i] * prices[i]
    }

    // Try to improve the profit by modifying exactly k consecutive elements
    for (i in 0 until n - k + 1) {
        // Original contribution of the k elements
        var originalContribution = 0L
        for (j in i until i + k) {
            originalContribution += strategy[j] * prices[j]
        }

        // New contribution after modifying the k elements
        var newContribution = 0L
        // First k/2 elements are 0 (hold), so no contribution
        // Last k/2 elements are 1 (sell), so add prices[i + k/2 ... i + k - 1]
        for (j in i + k / 2 until i + k) {
            newContribution += prices[j]
        }

        // Calculate the difference and update maxProfit if needed
        val diff = newContribution - originalContribution
        if (diff > 0) {
            maxProfit = maxOf(maxProfit, maxProfit + diff)
        }
    }

    return maxProfit
